#include <stdio.h>
#include <stdlib.h>

int main() {
    // Allocate memory for one integer on the heap
    int *ptr = (int *)malloc(sizeof(int));

    // Check if allocation succeeded
    if (ptr == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Assign value through dereferencing the pointer
    *ptr = 42;

    // Print the value
    printf("Value stored: %d\n", *ptr);
    printf("Address stored: %p\n", (void *)ptr);

    // Free the dynamically allocated memory
    free(ptr);
    ptr = NULL; // Good practice: avoid dangling pointer

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int size = 3;
    int count = 0;

    // Initially allocate memory for 3 integers
    int *arr = (int *)malloc(size * sizeof(int));

    if (arr == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Add elements to array
    int values[] = {10, 20, 30, 40, 50};

    for (int i = 0; i < 5; i++) {
        // Check if array is full, double the size if needed
        if (count == size) {
            size *= 2;
            int *temp = (int *)realloc(arr, size * sizeof(int));

            if (temp == NULL) {
                printf("Reallocation failed!\n");
                free(arr);
                return 1;
            }
            arr = temp;
            printf("Array resized to %d elements\n", size);
        }
        arr[count++] = values[i];
    }

    // Print all elements
    printf("\nDynamic Array Contents:\n");
    for (int i = 0; i < count; i++) {
        printf("arr[%d] = %d\n", i, arr[i]);
    }

    printf("\nFinal size: %d, Elements: %d\n", size, count);

    // Free the allocated memory
    free(arr);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

// Define node structure
struct Node {
    int data;
    struct Node *next;
};

// Function to create a new node
struct Node* createNode(int value) {
    struct Node *newNode = (struct Node *)malloc(sizeof(struct Node));

    if (newNode == NULL) {
        printf("Memory allocation failed!\n");
        return NULL;
    }

    newNode->data = value;
    newNode->next = NULL;

    return newNode;
}

// Function to insert at end of list
void insertAtEnd(struct Node **head, int value) {
    struct Node *newNode = createNode(value);

    if (*head == NULL) {
        *head = newNode;
        return;
    }

    struct Node *temp = *head;
    while (temp->next != NULL) {
        temp = temp->next;
    }
    temp->next = newNode;
}

// Function to free entire linked list (prevents memory leak)
void freeList(struct Node *head) {
    struct Node *temp;

    while (head != NULL) {
        temp = head;
        head = head->next;
        printf("Freeing node with data: %d\n", temp->data);
        free(temp);
    }
}

// Function to display list
void displayList(struct Node *head) {
    if (head == NULL) {
        printf("List is empty.\n");
        return;
    }

    printf("Linked List: ");
    while (head != NULL) {
        printf("%d ", head->data);
        head = head->next;
    }
    printf("\n");
}

int main() {
    struct Node *head = NULL;

    // Insert elements dynamically
    insertAtEnd(&head, 10);
    insertAtEnd(&head, 20);
    insertAtEnd(&head, 30);
    insertAtEnd(&head, 40);
    insertAtEnd(&head, 50);

    printf("Created a linked list with dynamic memory allocation:\n");
    displayList(head);

    // Demonstrate pointer to pointer for head modification
    printf("\nInserting 25 after 20...\n");
    // Note: For simplicity, using insertAtEnd - could add insertAfter
    insertAtEnd(&head, 25);
    displayList(head);

    // CRITICAL: Free all dynamically allocated memory
    printf("\nFreeing all nodes:\n");
    freeList(head);
    head = NULL;

    printf("\nMemory successfully freed.\n");

    return 0;
}
